commits.content:
/* Color Palette */
$primary-green: #00b14f;
$light-green: #eaf9f1;
$white: #ffffff;
$border-color: #e9eaee;
$text-main: #333333;
$text-muted: #666666;

.candidate-detail {
  background-color: $white;
  border-radius: 12px;
  overflow: hidden;
  font-family: 'Inter', sans-serif;
  color: $text-main;

  /* Header Section */
  &__top {
    padding: 24px;
    border-bottom: 1px solid $border-color;
    display: flex;
    justify-content: space-between;
    align-items: center;
    background: linear-gradient(to right, $white, $light-green);

    .top-left {
      display: flex;
      gap: 20px;
      align-items: center;

      .avatar-wrap {
        position: relative;
        .avatar {
          width: 80px;
          height: 80px;
          border-radius: 50%;
          border: 3px solid $white;
          box-shadow: 0 4px 10px rgba(0,0,0,0.1);
          object-fit: cover;
        }
        .online-dot {
          position: absolute;
          bottom: 5px;
          right: 5px;
          width: 14px;
          height: 14px;
          background: #28a745;
          border: 2px solid $white;
          border-radius: 50%;
        }
      }

      .info {
        .name {
          font-size: 20px;
          font-weight: 700;
          color: $primary-green;
          margin-bottom: 4px;
        }
        .meta {
          font-size: 14px;
          color: $text-muted;
          .sep { margin: 0 8px; }
        }
        .rating-row {
          margin-top: 8px;
          display: flex;
          gap: 6px;
          flex-wrap: wrap;
          .pill {
            background: $white;
            border: 1px solid $border-color;
            padding: 2px 8px;
            border-radius: 4px;
            font-size: 12px;
            color: $text-muted;
          }
        }
      }
    }
  }

  /* Scroll Area & Form */
  &__scroll {
    padding: 24px;
    max-height: 65vh;
    overflow-y: auto;

    .grid {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 20px;
    }

    .field {
      &.full { grid-column: span 2; }
      
      .label {
        font-weight: 600;
        font-size: 14px;
        margin-bottom: 8px;
        color: $text-main;
      }

      .input, .textarea, .form-control {
        width: 100%;
        padding: 10px 14px;
        border: 1px solid $border-color;
        border-radius: 8px;
        background-color: #f9f9f9;
        transition: all 0.3s;

        &:focus {
          outline: none;
          border-color: $primary-green;
          background-color: $white;
          box-shadow: 0 0 0 3px rgba(0, 177, 79, 0.1);
        }

        &.input-readonly {
          background-color: #f1f1f1;
          cursor: not-allowed;
        }
      }
    }
  }

  /* Experience Card Custom */
  .card {
    background: $light-green;
    border-radius: 12px;
    padding: 20px;
    border: 1px dashed $primary-green;

    &-row {
      margin-bottom: 15px;
      &:last-child { margin-bottom: 0; }
      &.two {
        display: grid;
        grid-template-columns: 1fr 1fr;
        gap: 15px;
      }
    }

    &-label {
      font-size: 13px;
      color: $primary-green;
      font-weight: 600;
      text-transform: uppercase;
      margin-bottom: 4px;
    }

    &-value {
      font-size: 15px;
      color: $text-main;
    }
  }

  /* Buttons */
  .btn {
    padding: 10px 20px;
    border-radius: 8px;
    font-weight: 600;
    cursor: pointer;
    transition: opacity 0.2s;
    border: none;

    &-green {
      background-color: $primary-green;
      color: $white;
      &:hover { opacity: 0.9; }
    }

    &-outline-blue { // Đổi tên thành outline-green cho đúng tone
      background: transparent;
      border: 1.5px solid $primary-green;
      color: $primary-green;
      &:hover { background: $light-green; }
    }
    
    &-blue { // Đổi tên thành solid-green
      background-color: $primary-green;
      color: white;
    }

    &-disabled {
      background-color: #ccc !important;
      cursor: not-allowed;
    }
  }

  &__footer {
    padding: 20px 24px;
    border-top: 1px solid $border-color;
    display: flex;
    gap: 15px;
    .w-50 { flex: 1; }
  }
}
